data:
/// サーバー情報ウィジェット
/// 接続中のサーバーのメタ情報を表示します。

Ui:render([
  Ui:C:mfm({ text: "<center>$[fg.color=888888 読み込み中...]</center>" })
])

let serverInfo = Mk:api("meta", {})

let info = `<center>$[x2 **{serverInfo.name}**]
<small>{serverInfo.description}</small></center>

ユーザー数: **{serverInfo.originalUsersCount}**
ノート数: **{serverInfo.originalNotesCount}**
バージョン: **v{serverInfo.version}**`

Ui:render([
  Ui:C:container({
    children: [
      Ui:C:mfm({ text: info })
    ]
  })
])
